// SessionData represents the data stored in a user session.
type SessionData struct {
	ID           string
	UserID       string
	Preferences  map[string]string
	Permissions  []string
	CreatedAt    time.Time
	LastAccessed time.Time
	ExpiresAt    time.Time // When the session will expire if not accessed
}

// SessionStore defines the interface for session management operations.
type SessionStore interface {
	NewSession(userID string, preferences map[string]string, permissions []string) (*SessionData, error)
	Get(sessionID string) (*SessionData, error)
	Set(session *SessionData) error
	Delete(sessionID string) error
	Stop() // To gracefully stop background tasks
}

const (
	DefaultSessionExpiration = 30 * time.Minute
	DefaultCleanupInterval   = 5 * time.Minute
	DefaultPersistInterval   = 1 * time.Minute // Periodic full save for robustness
	SessionFileExtension     = ".gob"
)

var (
	ErrSessionNotFound = errors.New("session not found")
	ErrSessionExpired  = errors.New("session expired")
	ErrSessionCorrupt  = errors.New("session data corrupted or invalid")
)

// DiskGobStore implements SessionStore, storing sessions as gob files on disk.
type DiskGobStore struct {
	mu              sync.RWMutex
	sessions        map[string]*SessionData // In-memory cache of active sessions
	sessionDir      string
	stopChan        chan struct{}
	doneChan        chan struct{}
	sessionTTL      time.Duration // Time-to-live for sessions
	cleanupInterval time.Duration
	persistInterval time.Duration
}

// NewDiskGobStore creates and initializes a new DiskGobStore.
// It loads existing sessions from the specified directory and starts background cleanup/persistence tasks.
func NewDiskGobStore(sessionDir string, options ...func(*DiskGobStore)) (*DiskGobStore, error) {
	// Ensure gob knows how to encode/decode SessionData
	gob.Register(SessionData{})

	store := &DiskGobStore{
		sessions:        make(map[string]*SessionData),
		sessionDir:      sessionDir,
		stopChan:        make(chan struct{}),
		doneChan:        make(chan struct{}),
		sessionTTL:      DefaultSessionExpiration,
		cleanupInterval: DefaultCleanupInterval,
		persistInterval: DefaultPersistInterval,
	}

	for _, opt := range options {
		opt(store)
	}

	if err := os.MkdirAll(sessionDir, 0755); err != nil {
		return nil, fmt.Errorf("failed to create session directory %s: %w", sessionDir, err)
	}

	if err := store.loadAllSessions(); err != nil {
		fmt.Printf("Warning: Failed to load some sessions during startup: %v\n", err)
	}

	go store.startBackgroundTasks()

	return store, nil
}

// WithSessionTTL allows setting a custom session Time-To-Live.
func WithSessionTTL(ttl time.Duration) func(*DiskGobStore) {
	return func(s *DiskGobStore) {
		s.sessionTTL = ttl
	}
}

// WithCleanupInterval allows setting a custom cleanup interval.
func WithCleanupInterval(interval time.Duration) func(*DiskGobStore) {
	return func(s *DiskGobStore) {
		s.cleanupInterval = interval
	}
}

// WithPersistInterval allows setting a custom persistence interval.
func WithPersistInterval(interval time.Duration) func(*DiskGobStore) {
	return func(s *DiskGobStore) {
		s.persistInterval = interval
	}
}

// NewSession creates a new session, assigns a unique ID, and saves it.
func (s *DiskGobStore) NewSession(userID string, preferences map[string]string, permissions []string) (*SessionData, error) {
	sessionID := uuid.New().String()
	now := time.Now()
	session := &SessionData{
		ID:           sessionID,
		UserID:       userID,
		Preferences:  preferences,
		Permissions:  permissions,
		CreatedAt:    now,
		LastAccessed: now,
		ExpiresAt:    now.Add(s.sessionTTL),
	}

	if err := s.Set(session); err != nil {
		return nil, fmt.Errorf("failed to save new session: %w", err)
	}
	return session, nil
}

// Get retrieves a session by its ID. Updates LastAccessed if found and not expired.
func (s *DiskGobStore) Get(sessionID string) (*SessionData, error) {
	s.mu.RLock()
	session, found := s.sessions[sessionID]
	s.mu.RUnlock()

	if !found {
		// Attempt to load from disk if not in memory (e.g., store was restarted)
		loadedSession, err := s.loadSessionFromFile(sessionID)
		if err != nil {
			if errors.Is(err, ErrSessionNotFound) || errors.Is(err, ErrSessionExpired) {
				// If not found or already expired on disk, return corresponding error
				return nil, err
			}
			return nil, fmt.Errorf("failed to load session from disk: %w", err)
		}
		session = loadedSession
		found = true
	}

	if found {
		if session.ExpiresAt.Before(time.Now()) {
			// Session found but expired, delete it from memory and disk
			s.Delete(sessionID)
			return nil, ErrSessionExpired
		}

		// Update LastAccessed and ExpiresAt
		session.LastAccessed = time.Now()
		session.ExpiresAt = session.LastAccessed.Add(s.sessionTTL)

		// Persist the updated session. Calling Set acquires a write lock and saves.
		err := s.Set(session)
		if err != nil {
			return nil, fmt.Errorf("failed to update session on get: %w", err)
		}

		return session, nil
	}

	return nil, ErrSessionNotFound
}

// Set stores or updates a session. It saves the session to disk immediately.
func (s *DiskGobStore) Set(session *SessionData) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	s.sessions[session.ID] = session
	return s.saveSessionToFile(session)
}

// Delete removes a session from memory and disk.
func (s *DiskGobStore) Delete(sessionID string) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	delete(s.sessions, sessionID)
	return s.deleteSessionFile(sessionID)
}

// Stop gracefully stops the background tasks of the store.
func (s *DiskGobStore) Stop() {
	close(s.stopChan)
	<-s.doneChan // Wait for background tasks to finish
	fmt.Println("DiskGobStore background tasks stopped.")
}

// startBackgroundTasks runs periodic cleanup and persistence.
func (s *DiskGobStore) startBackgroundTasks() {
	defer close(s.doneChan)

	cleanupTicker := time.NewTicker(s.cleanupInterval)
	persistTicker := time.NewTicker(s.persistInterval)
	defer cleanupTicker.Stop()
	defer persistTicker.Stop()

	for {
		select {
		case <-cleanupTicker.C:
			s.cleanupExpiredSessions()
		case <-persistTicker.C:
			// Periodically save all sessions currently in memory.
			// This acts as a robustness measure, ensuring sessions are saved
			// even if 'Set' isn't explicitly called frequently after modification.
			s.saveAllSessions()
		case <-s.stopChan:
			fmt.Println("Shutting down background tasks. Saving all sessions...")
			s.saveAllSessions() // Ensure all current sessions are saved on shutdown
			return
		}
	}
}

// cleanupExpiredSessions removes expired sessions from memory and disk.
func (s *DiskGobStore) cleanupExpiredSessions() {
	s.mu.Lock()
	defer s.mu.Unlock()

	now := time.Now()
	deletedCount := 0
	for id, session := range s.sessions {
		if session.ExpiresAt.Before(now) {
			delete(s.sessions, id)
			s.deleteSessionFile(id) // Attempt to delete from disk
			deletedCount++
		}
	}
	if deletedCount > 0 {
		fmt.Printf("Cleaned up %d expired sessions.\n", deletedCount)
	}
}

// saveSessionToFile writes a single session to a gob file.
func (s *DiskGobStore) saveSessionToFile(session *SessionData) error {
	filePath := filepath.Join(s.sessionDir, session.ID+SessionFileExtension)
	file, err := os.Create(filePath)
	if err != nil {
		return fmt.Errorf("failed to create session file %s: %w", filePath, err)
	}
	defer file.Close()

	encoder := gob.NewEncoder(file)
	if err := encoder.Encode(session); err != nil {
		return fmt.Errorf("failed to encode session %s to file %s: %w", session.ID, filePath, err)
	}
	return nil
}

// loadSessionFromFile loads a single session from a gob file.
func (s *DiskGobStore) loadSessionFromFile(sessionID string) (*SessionData, error) {
	filePath := filepath.Join(s.sessionDir, sessionID+SessionFileExtension)
	file, err := os.Open(filePath)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, ErrSessionNotFound
		}
		return nil, fmt.Errorf("failed to open session file %s: %w", filePath, err)
	}
	defer file.Close()

	decoder := gob.NewDecoder(file)
	var session SessionData
	if err := decoder.Decode(&session); err != nil {
		// Clean up potentially corrupted file
		_ = os.Remove(filePath) // Ignore error on remove
		return nil, fmt.Errorf("%w for session file %s: %v. File removed.", ErrSessionCorrupt, filePath, err)
	}

	// Double-check expiration upon load, don't return expired sessions.
	if session.ExpiresAt.Before(time.Now()) {
		// Clean up expired file as well
		_ = os.Remove(filePath) // Ignore error on remove
		return nil, ErrSessionExpired
	}

	return &session, nil
}

// deleteSessionFile removes a session's gob file from disk.
func (s *DiskGobStore) deleteSessionFile(sessionID string) error {
	filePath := filepath.Join(s.sessionDir, sessionID+SessionFileExtension)
	if err := os.Remove(filePath); err != nil && !os.IsNotExist(err) {
		return fmt.Errorf("failed to delete session file %s: %w", filePath, err)
	}
	return nil
}

// saveAllSessions writes all sessions currently in memory to disk.
func (s *DiskGobStore) saveAllSessions() {
	s.mu.RLock()
	sessionsToSave := make([]*SessionData, 0, len(s.sessions))
	for _, session := range s.sessions {
		sessionsToSave = append(sessionsToSave, session)
	}
	s.mu.RUnlock()

	// Perform actual file operations outside the global lock
	for _, session := range sessionsToSave {
		if err := s.saveSessionToFile(session); err != nil {
			fmt.Printf("Error saving session %s to disk: %v\n", session.ID, err)
		}
	}
}

// loadAllSessions loads all existing session gob files from disk into memory.
func (s *DiskGobStore) loadAllSessions() error {
	files, err := ioutil.ReadDir(s.sessionDir)
	if err != nil {
		return fmt.Errorf("failed to read session directory %s: %w", s.sessionDir, err)
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	var loadErrors []error
	loadedCount := 0
	for _, file := range files {
		if file.IsDir() || filepath.Ext(file.Name()) != SessionFileExtension {
			continue
		}

		sessionID := file.Name()[:len(file.Name())-len(SessionFileExtension)]
		session, err := s.loadSessionFromFile(sessionID)
		if err != nil {
			loadErrors = append(loadErrors, fmt.Errorf("failed to load session %s: %w", sessionID, err))
			continue
		}
		s.sessions[session.ID] = session
		loadedCount++
	}

	if len(loadErrors) > 0 {
		return fmt.Errorf("encountered %d errors during session loading, loaded %d: %v", len(loadErrors), loadedCount, loadErrors)
	}
	fmt.Printf("Loaded %d sessions from disk.\n", loadedCount)
	return nil
}

